@@ -382,28 +382,29 @@ asx_status asx_runtime_reactor_wait(uint32_t timeout_ms, uint32_t *out_ready_cou
     if (!out_ready_count) return ASX_E_INVALID_ARGUMENT;
     if (!g_hooks_installed) return ASX_E_HOOK_MISSING;

-    /* Prefer an installed native reactor hook so callers do not have to
-     * explicitly clear the default ghost hook to reach live I/O paths. */
-    if (g_hooks.reactor.wait_fn) {
-        asx_status rs_ = g_hooks.reactor.wait_fn(g_hooks.reactor.ctx, timeout_ms, out_ready_count);
+#if ASX_DETERMINISTIC
+    /* In deterministic mode, prefer the ghost reactor for reproducibility. */
+    if (g_hooks.reactor.ghost_wait_fn) {
+        asx_status rs_ =
+            g_hooks.reactor.ghost_wait_fn(g_hooks.reactor.ctx, logical_step, out_ready_count);
         if (rs_ == ASX_OK) {
             asx_hindsight_log(*out_ready_count > 0 ? ASX_ND_IO_READY : ASX_ND_IO_TIMEOUT, 0,
                               (uint64_t)*out_ready_count);
         }
         return rs_;
     }
+#endif

-#if ASX_DETERMINISTIC
-    if (g_hooks.reactor.ghost_wait_fn) {
-        asx_status rs_ =
-            g_hooks.reactor.ghost_wait_fn(g_hooks.reactor.ctx, logical_step, out_ready_count);
+    /* Fall back to native reactor hook for live I/O paths. */
+    if (g_hooks.reactor.wait_fn) {
+        asx_status rs_ = g_hooks.reactor.wait_fn(g_hooks.reactor.ctx, timeout_ms, out_ready_count);
         if (rs_ == ASX_OK) {
             asx_hindsight_log(*out_ready_count > 0 ? ASX_ND_IO_READY : ASX_ND_IO_TIMEOUT, 0,
                               (uint64_t)*out_ready_count);
         }
         return rs_;
     }
-#endif
+
     return ASX_E_HOOK_MISSING;
 }

@@ -51,8 +51,14 @@ TEST(summary_tracks_counts_and_obligations) {
     ASSERT_EQ(summary.requests_sent, 1u);
     ASSERT_EQ(asx_link_recv_request(&link, &value), ASX_OK);
     ASSERT_EQ(asx_link_capture_summary(&link, &summary), ASX_OK);
-    ASSERT_EQ(summary.outstanding_obligations, 0u);
+    /* Obligations persist until initiator receives the response. */
+    ASSERT_EQ(summary.outstanding_obligations, 1u);
     ASSERT_EQ(summary.requests_received, 1u);
+    /* Complete the cycle: respond and receive response. */
+    ASSERT_EQ(asx_link_send_response(&link, 7u), ASX_OK);
+    ASSERT_EQ(asx_link_recv_response(&link, &value), ASX_OK);
+    ASSERT_EQ(asx_link_capture_summary(&link, &summary), ASX_OK);
+    ASSERT_EQ(summary.outstanding_obligations, 0u);
     asx_link_close(&link);
     teardown();
 }

@@ -432,9 +432,17 @@ TEST(reactor_wait_prefers_native_hook_when_both_are_installed) {
     ASSERT_EQ(asx_runtime_set_hooks(&hooks), ASX_OK);

     ASSERT_EQ(asx_runtime_reactor_wait(100, &ready, 5), ASX_OK);
+#if ASX_DETERMINISTIC
+    /* In deterministic mode, ghost reactor takes priority for reproducibility. */
+    ASSERT_EQ(ready, 3u);
+    ASSERT_EQ(g_reactor_count, 1);
+    ASSERT_EQ(g_native_reactor_count, 0);
+#else
+    /* In non-deterministic mode, native reactor takes priority for live I/O. */
     ASSERT_EQ(ready, 7u);
     ASSERT_EQ(g_native_reactor_count, 1);
     ASSERT_EQ(g_reactor_count, 0);
+#endif
 }

